	"sourcesContent": [
		"//\n// IMPORTS\n//\n\n//@import \"reset\";\n//@import \"variables\";\n// Syntax highlighting @import is at the bottom of this file\n\n/**************/\n/* BASE RULES */\n/**************/\na {\n  color: #1772d0;\n  text-decoration: none;\n}\n\na:focus,\na:hover {\n  color: #f09228;\n  text-decoration: none;\n}\n\nbody,\ntd,\nth,\ntr,\np,\na {\n  font-family: 'Lato', Verdana, Helvetica, sans-serif;\n  font-size: 14px;\n  font-display: auto;\n}\n\nstrong {\n  font-family: 'Lato', Verdana, Helvetica, sans-serif;\n  font-size: 14px;\n  font-display: auto;\n}\n\nh2 {\n  font-family: 'Lato', Verdana, Helvetica, sans-serif;\n  font-size: 22px;\n  font-display: auto;\n  font-weight: normal;\n  padding: 0px;\n  margin: 0px;\n  display:inline; \n}\n\nh3 {\n  font-family: 'Lato', Verdana, Helvetica, sans-serif;\n  font-size: 14px;\n  font-weight: 700;\n  font-display: auto;\n  padding: 0px;\n  margin: 0px;\n  display:inline; \n}\n\nh1 {\n  font-family: 'Lato', Verdana, Helvetica, sans-serif;\n  font-size: 32px;\n  font-weight: normal;\n  font-display: auto;\n  text-align: center;\n  padding: 0px;\n  margin-block-start: 14px;\n  margin-block-end: 14px;\n  margin-left: 0px;\n  margin-right: 0px;\n\n}\n\n.one {\n  width: 160px;\n  height: 160px;\n  position: relative;\n}\n\n.two {\n  width: 160px;\n  height: 160px;\n  position: absolute;\n  transition: opacity .2s ease-in-out;\n  -moz-transition: opacity .2s ease-in-out;\n  -webkit-transition: opacity .2s ease-in-out;\n}\n\n.fade {\n  transition: opacity .2s ease-in-out;\n  -moz-transition: opacity .2s ease-in-out;\n  -webkit-transition: opacity .2s ease-in-out;\n}\n\nspan.highlight {\n  background-color: #ffffd0;\n}\n\n// Settled on moving the import of syntax highlighting to the bottom of the CSS\n// ... Otherwise it really bloats up the top of the CSS file and makes it difficult to find the start\n//@import \"highlights\";\n//@import \"svg-icons\";\n.impact-card{\n  margin-top: 28px;\n  padding: 22px 22px;\n  border: 1px solid rgba(0,0,0,0.08);\n  border-radius: 14px;\n  background: rgba(0,0,0,0.02);\n  box-shadow: 0 8px 24px rgba(0,0,0,0.06);\n  border-left: 5px solid rgba(0,0,0,0.25);\n}\n\n.impact-title{\n  font-size: 20px;\n  font-weight: 700;\n  line-height: 1.25;\n  margin-bottom: 8px;\n}\n\n.impact-subtitle{\n  font-size: 15px;\n  color: rgba(0,0,0,0.70);\n  line-height: 1.45;\n  margin-bottom: 14px;\n}\n\n.impact-section{\n  font-size: 13px;\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n  color: rgba(0,0,0,0.55);\n  margin-bottom: 10px;\n}\n\n.impact-list{\n  margin: 0;\n  padding-left: 18px;\n}\n\n.impact-list li{\n  margin: 8px 0;\n  line-height: 1.4;\n}\n"
	],
